1	export interface QuoteItem {
2	  type: string;
3	}
4	
5	export interface QuoteInput {
6	  items: QuoteItem[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	};
19	
20	export function quote(input: QuoteInput): number {
21	  if (input.items.length === 0) return PROCESSING_FEE;
22	  const item = input.items[0];
23	  const base = BASE_PREMIUM[item.type];
24	  const itemPremium = base + base * FIRST_INSURANCE_RATE;
25	  return itemPremium + PROCESSING_FEE;
26	}
27	
28	export function claim() {
29	  return undefined;
30	}
